aceita_rejeita <- function(n, f, g_amostra, g_dens, c) {
  amostra    <- numeric(n)
  aceites    <- 0
  tentativas <- 0
  while (aceites < n) {
    y <- g_amostra(1)              # observação da proposta
    u <- runif(1)                  # uniforme para o teste
    tentativas <- tentativas + 1
    if (u <= f(y) / (c * g_dens(y))) {
      aceites <- aceites + 1
      amostra[aceites] <- y
    }
  }
  list(amostra = amostra,
       taxa_aceitacao = aceites / tentativas)
}

